/**
 * Calculates an objective avalanche risk score based on various backcountry factors.
 * @param {object} inputs - An object containing all input values.
 * @returns {object} An object containing the avalancheRiskScore, riskCategory, and recommendation.
 */
function calculateAvalancheRisk(inputs) {
  let score = 0;

  // 1. Base Score from AIARE Danger Rating
  switch (inputs.aiareDangerRating) {
    case 'Low': score += 10; break;
    case 'Moderate': score += 30; break;
    case 'Considerable': score += 60; break;
    case 'High': score += 90; break;
    case 'Extreme': score += 120; break;
    default: score += 0; // Should not happen with validation
  }

  // 2. Adjust for Terrain Angle
  const terrainAngle = parseFloat(inputs.terrainAngle);
  if (terrainAngle < 25) { score -= 5; } // Generally safe from slab avalanches
  else if (terrainAngle >= 25 && terrainAngle <= 29) { score += 0; } // Can slide, less common
  else if (terrainAngle >= 30 && terrainAngle <= 34) { score += 10; } // Common avalanche angle
  else if (terrainAngle >= 35 && terrainAngle <= 39) { score += 20; } // Very common, often active
  else if (terrainAngle >= 40 && terrainAngle <= 45) { score += 30; } // Steep, frequently active
  else if (terrainAngle > 45) { score += 40; } // Extreme terrain, high risk
  score = Math.max(0, score); // Ensure score doesn't go negative from terrain initially

  // 3. Adjust for Aspect (simplified: N/NE/NW often colder/wind-loaded, S/SE/SW can be solar-affected)
  switch (inputs.aspect) {
    case 'N':
    case 'NE':
    case 'NW': score += 5; break; // Can hold persistent slabs, often wind-loaded
    case 'S':
    case 'SE':
    case 'SW': score -= 5; break; // Can stabilize faster with sun, but prone to wet slides later season
    case 'E':
    case 'W': score += 0; break;
    default: score += 0; 
  }

  // 4. Adjust for Elevation Band
  switch (inputs.elevationBand) {
    case 'Below Treeline': score += 0; break;
    case 'Near Treeline': score += 5; break;
    case 'Above Treeline': score += 15; break; // More exposed, colder, less anchor points
    default: score += 0; 
  }

  // 5. Adjust for Recent Snowfall (24h)
  const recentSnowfall24h = parseFloat(inputs.recentSnowfall24h);
  if (recentSnowfall24h <= 5) { score += 0; }
  else if (recentSnowfall24h <= 15) { score += 10; }
  else if (recentSnowfall24h <= 30) { score += 20; }
  else if (recentSnowfall24h <= 50) { score += 35; }
  else if (recentSnowfall24h > 50) { score += 50; } // Significant loading, high instability

  // 6. Adjust for Recent Wind Loading
  switch (inputs.recentWindLoading) {
    case 'None': score += 0; break;
    case 'Minor/Localized': score += 15; break;
    case 'Significant/Widespread': score += 30; break; // Wind slabs are a primary hazard
    default: score += 0; 
  }

  // 7. Adjust for Observed Snowpack Stability Test Results
  switch (inputs.snowpackStabilityTest) {
    case 'Good (ECTN, PSTN)': score -= 15; break; // Strong evidence of stability
    case 'Fair (ECTP, PSTP)': score += 20; break; // Some signs of instability, caution needed
    case 'Poor (ECTX, PSTX)': score += 40; break; // Clear signs of instability, high danger
    default: score += 0; 
  }

  // 8. Adjust for Group's Overall Backcountry Experience & Training
  switch (inputs.groupExperience) {
    case 'Beginner (No formal training)': score += 15; break; // Higher risk of errors, less awareness
    case 'Intermediate (AIARE L1 equivalent)': score += 0; break;
    case 'Advanced (AIARE L2 equivalent)': score -= 5; break;
    case 'Expert (Professional/Extensive experience)': score -= 10; break; // Better decision-making, rescue skills
    default: score += 0; 
  }

  // Cap the score to a reasonable maximum (e.g., 150-180 for extreme conditions)
  score = Math.min(score, 180); 

  let riskCategory;
  let recommendation;

  if (score < 20) {
    riskCategory = 'Very Low';
    recommendation = 'Conditions appear relatively stable, but constant vigilance and reassessment are always required. Enjoy the trip responsibly.';
  } else if (score >= 20 && score <= 40) {
    riskCategory = 'Low';
    recommendation = 'General avalanche danger is low. However, local variability can exist. Remain alert for changing conditions and terrain traps.';
  } else if (score > 40 && score <= 70) {
    riskCategory = 'Moderate';
    recommendation = 'Moderate avalanche danger. Carefully plan your route to avoid or minimize exposure to avalanche terrain. Carry and know how to use all safety gear.';
  } else if (score > 70 && score <= 100) {
    riskCategory = 'Considerable';
    recommendation = 'Considerable avalanche danger. Travel in avalanche terrain is NOT recommended for inexperienced groups. Experts should exercise extreme caution, stick to simple terrain, and be prepared to turn back.';
  } else if (score > 100 && score <= 130) {
    riskCategory = 'High';
    recommendation = 'High avalanche danger. Travel in avalanche terrain is NOT RECOMMENDED. Widespread dangerous avalanche conditions exist. Consider alternative activities or postpone your trip.';
  } else {
    riskCategory = 'Extreme';
    recommendation = 'Extreme avalanche danger. AVOID ALL BACKCOUNTRY TRAVEL. Natural avalanches are expected. Conditions are exceptionally dangerous and unforgiving. Postpone your trip.';
  }

  return {
    avalancheRiskScore: Math.round(score),
    riskCategory: riskCategory,
    recommendation: recommendation
  };
}
